from collections import Counter
from math import gcd

class Solution:
    def minGroupsForValidAssignment(self, nums: List[int]) -> int:
        count = Counter(nums)
        values = list(count.values())

        # Find the maximum possible group size that divides all frequencies
        max_group_size = values[0]
        for v in values[1:]:
            max_group_size = gcd(max_group_size, v)

        # Calculate the minimum number of groups
        return sum(v // max_group_size for v in values)
